export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "05:47。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是 07:05。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "天還沒有全亮。雨停了。操場上的積水映著灰藍色的天。教學樓的輪廓在晨霧裡，像一幅還沒有乾的水彩。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在教學樓頂樓的平台上。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有睡。不是睡不著——是沒有去睡。23:00 過去之後，他在後台通道裡坐了很久。許星棠在旁邊。韓越在旁邊。沒有人說話。他們只是坐在那裡，聽著禮堂裡的混亂慢慢被外部警員和家長接管，聽著雨聲慢慢變小，聽著夜慢慢過去。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "凌晨兩點，許星棠的母親的舊同事從市區趕到了。她是一個頭髮花白的女人，手裡拿著一個檔案袋。她看見許星棠的時候沒有哭。她只是把檔案袋遞給她，說了一句：「你媽的東西，我留了十年。」", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "凌晨三點，韓越的父親開車到了。他沒有問發生了什麼。他只是看見韓越坐在通道裡，然後蹲下來，和他一起坐了一會兒。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "凌晨四點，顧言一個人上了頂樓。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他需要看見天亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他需要確認——天會亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在欄杆上。欄杆是濕的。他的校服肩膀靠上去的時候，涼意透進來。他沒有動。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "東邊的天在亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是突然的亮。是那種——從灰藍變成灰白、從灰白變成淡黃、從淡黃慢慢滲出一點橘色的亮。很慢。像有人在很遠的地方，一層一層地掀開窗簾。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著那片光。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了七次 07:05 的天花板。七次同一道裂紋。七次同一場雨。七次同一則訊息。七次同一個早晨。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這是他第一次看見 05:47 的天。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是他第一次看見天亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是從窗戶裡看見的。是站在外面。站在雨停之後的空氣裡。站在風裡。站在一個沒有天花板的地方。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）爸說——不要回頭看火，去看海上的燈。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我看了七次火。我看了七次許星棠倒下。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我看了七次白色。我看了七次 07:05。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但這一次——", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他往東看。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "越過小鎮的屋頂。越過港口的燈桿。越過防波堤。越過灰色的海面。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很遠的地方。海和天交界的地方。有一點光。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是太陽。太陽還沒有出來。是那種——太陽還在海平面下面、但光已經開始往上滲的時候，海面上會出現的一點亮。很淡。很遠。像有人在很遠很遠的地方點了一盞燈。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海上的燈。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言看著它。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的眼眶又熱了。但這一次不是憋不住的熱。是那種——終於看見了什麼東西的熱。那種找了很久才看見的熱。不是悲傷。不是解脫。是更安靜的東西。是「它在那裡」的熱。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）它在那裡。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）一直在那裡。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身後有腳步聲。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很輕。不是邵叔那種帶著目的的腳步聲。不是韓越那種急切的腳步聲。是那種——不確定自己該不該上來、但還是上來了的腳步聲。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有回頭。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲停在他旁邊。隔了一步的距離。不是並肩。是那種——我在這裡，但我不打擾你——的距離。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有說話。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她也靠在欄杆上。她的相機掛在脖子上。她沒有舉起來。她只是站著。看著同一個方向。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個人。一步的距離。看著東邊。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海面上的那點光在變亮。很慢。從淡橘變成橘黃。從橘黃開始有一點金。海面被它染出一條很細的亮帶，從防波堤一直延伸到天邊。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的聲音很輕。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你爸的那段錄音。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.XuXingtang_Regretful },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "他說——不要回頭看火，去看海上的燈。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.XuXingtang_Regretful },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有立刻接話。她看著海面上的光。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你看了嗎。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.XuXingtang_Regretful },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有立刻回答。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著那點光。看著它從橘黃變成金色。看著海面上的亮帶越來越寬。看著天從灰白變成淡藍。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了七次火。他看了七次白色。他看了七次同一個早晨的天花板。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次，他看見了燈。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "看了。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個字。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有再問。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個人站在那裡。看著天亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "太陽從海平面下面升上來了。不是一瞬間的事。是那種——先是海面上出現一道亮線，然後亮線中間鼓起來，然後一個橙紅色的邊緣露出來，然後整個圓慢慢地、慢慢地從海裡升起來。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "光打在兩個人的臉上。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暖的。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是螢幕的光。不是應急燈的光。是太陽的光。是 05:51 的太陽的光。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言閉上眼睛。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他讓光打在臉上。他讓暖意停在皮膚表面。他聽見海風從東邊吹過來，帶著一點鹹味。他聽見遠處有鳥在叫。他聽見許星棠旁邊的呼吸聲，很淺、很穩。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有醒來。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有醒來。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）也許這只是第八次。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但這一刻是真的。", background: Background.Chapter_8_Ch8_ActEpilogue_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他只是站在那裡。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站在 05:51 的天台上。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站在這一天的早晨裡。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站在明天的前面。", background: Background.Chapter_8_Ch8_ActEpilogue_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "05:55。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "天亮了。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是循環的天亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是這一天的天亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是 23:01 之後的天亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是下一分鐘、下一分鐘、下一分鐘——一直走到早晨的天亮。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言睜開眼睛。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海面上的燈不見了。不是滅了——是太陽出來之後，它就看不見了。它不需要再被看見了。它的作用是在黑暗裡告訴你方向。天亮了之後，你看見整片海。你看見防波堤。你看見港口。你看見小鎮的屋頂。你看見學校的操場。你看見所有東西。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "燈完成了它的工作。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它一直在那裡。在黑暗裡。在雨裡。在七次循環裡。在每一次 23:00 之後的白色裡。它一直在那裡。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言只是花了七次才看見它。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低下頭。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手伸進校服內側口袋。那個靠近胸口的位置。那個放過未裁切照片、放過備用記憶卡的位置。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裡面是空的。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "記憶卡在凌晨兩點的時候交給了許星棠母親的舊同事。她會把它和檔案袋一起帶走。和相機裡的原始檔案、和基座底板的影像、和門禁紀錄、和直播存檔一起——交給該看到的人。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "口袋空了。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但不是那種被掏空的空。是那種——東西已經到了該去的地方、手可以鬆開了的空。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的聲音從旁邊傳過來。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你說過——你不知道明天會怎樣。", background: Background.Chapter_8_Ch8_ActEpilogue_S2, portrait: Portrait.XuXingtang_Regretful },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_8_Ch8_ActEpilogue_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "現在呢。", background: Background.Chapter_8_Ch8_ActEpilogue_S2, portrait: Portrait.XuXingtang_Regretful },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言看著天亮的海面。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不知道明天會怎樣。他不知道邵叔會被怎麼處理。他不知道林主任會說什麼。他不知道學校會怎麼面對這件事。他不知道那些家長和媒體會把這件事變成什麼形狀。他不知道他和許星棠、和韓越之後會怎樣。他不知道自己會不會好起來。他不知道那些七次的記憶會變成什麼——會慢慢淡掉，還是會一直在那裡，像一道裂紋一樣留在某個看不見的地方。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不知道。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他站在這裡。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在 05:55 的天台上。太陽打在臉上。海風從東邊吹過來。許星棠站在一步之外。韓越大概在樓下，可能睡著了，可能也醒著。遠處有鳥在叫。遠處有車聲。遠處有小鎮醒來的聲音。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不知道明天會怎樣。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但明天在那裡。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "在。", background: Background.Chapter_8_Ch8_ActEpilogue_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個字。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有再說話。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點了一下頭。很小的動作。和 23:01 的時候一樣小。下巴往下，再回來。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聽見了。我相信你。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個人站在天台上。看著太陽升起來。看著小鎮醒過來。看著這一天的早晨——不是循環的早晨，不是重來的早晨，是 23:01 之後一分鐘一分鐘走過來的早晨——慢慢地、慢慢地展開。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "風從海面上吹過來。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "帶著鹹味。帶著光。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "帶著明天的味道。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "——", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海上的燈滅了。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "天亮了。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "故事在這裡停下。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是結束。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是下一分鐘。", background: Background.Chapter_8_Ch8_ActEpilogue_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "06:00。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從欄杆上直起身。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉過身。背對著海。背對著太陽。面向天台門。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門是開著的。樓梯間的聲音從下面傳上來。有人在走動。有人在說話。學校在醒。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠也轉過身。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個人往門口走。不是並肩。是一前一後。顧言在前。許星棠在後。一步的距離。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走進樓梯間的時候，沒有回頭看海。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不需要再看了。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "燈已經完成了它的工作。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "天已經亮了。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "明天已經在這裡了。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "——", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他往下走。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一步。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一步。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一步。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "每一步都是新的。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "每一步都是他沒有走過的。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "每一步都是 23:01 之後的下一分鐘。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "——", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "樓梯間的窗戶透進來早晨的光。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暖的。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有醒來。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他只是往前走。", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "——完——", background: Background.Chapter_8_Ch8_ActEpilogue_S3 },
];
